import React, { useState, useEffect } from 'react';
import { 
  FaMicrophone, 
  FaMicrophoneSlash, 
  FaVideo, 
  FaVideoSlash, 
  FaPhone, 
  FaSync, 
  FaComment,
  FaMinus,
  FaExpand 
} from 'react-icons/fa';

const VideoCallUI = ({ isOpen, onClose, doctor, callType = 'video' }) => {
  const [isMuted, setIsMuted] = useState(false);
  const [isVideoOn, setIsVideoOn] = useState(callType === 'video');
  const [callDuration, setCallDuration] = useState(0);
  const [isMinimized, setIsMinimized] = useState(false);

  useEffect(() => {
    if (!isOpen) return;
    
    const timer = setInterval(() => {
      setCallDuration(prev => prev + 1);
    }, 1000);

    return () => clearInterval(timer);
  }, [isOpen]);

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleEndCall = () => {
    setCallDuration(0);
    onClose();
  };

  if (!isOpen) return null;

  if (isMinimized) {
    return (
      <div className="fixed bottom-24 right-4 bg-white rounded-xl shadow-2xl border-2 border-blue-500 z-50 w-80">
        <div className="p-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-blue-600 rounded-full flex items-center justify-center text-white text-sm font-bold">
                {doctor?.name ? doctor.name.split(' ').map(n => n[0]).join('') : 'DR'}
              </div>
              <div>
                <p className="font-semibold text-sm">{doctor?.name || 'Doctor'}</p>
                <p className="text-xs text-green-600">{formatTime(callDuration)}</p>
              </div>
            </div>
            <div className="flex gap-2">
              <button
                onClick={() => setIsMinimized(false)}
                className="p-2 text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                aria-label="Expand call"
              >
                <FaExpand className="text-xs" />
              </button>
              <button
                onClick={handleEndCall}
                className="p-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition-colors"
                aria-label="End call"
              >
                <FaPhone className="text-xs" />
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 bg-gray-900 z-50 flex flex-col">
      {/* Call Header */}
      <div className="bg-gray-800 text-white p-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <h2 className="text-xl font-bold">
              {callType === 'video' ? 'Video Call' : 'Audio Call'}
            </h2>
            <div className="bg-green-500 px-3 py-1 rounded-full text-sm font-semibold">
              {formatTime(callDuration)}
            </div>
          </div>
          <button
            onClick={() => setIsMinimized(true)}
            className="p-2 text-gray-300 hover:text-white hover:bg-gray-700 rounded-lg transition-colors"
            aria-label="Minimize call"
          >
            <FaMinus />
          </button>
        </div>
      </div>

      {/* Video Area */}
      <div className="flex-1 relative">
        {callType === 'video' ? (
          <>
            {/* Remote Video (Doctor) */}
            <div className="w-full h-full bg-gray-800 flex items-center justify-center">
              <div className="text-center text-white">
                <div className="w-32 h-32 bg-gradient-to-br from-blue-500 to-blue-600 rounded-full flex items-center justify-center text-white text-4xl font-bold mx-auto mb-4">
                  {doctor?.name ? doctor.name.split(' ').map(n => n[0]).join('') : 'DR'}
                </div>
                <h3 className="text-2xl font-semibold">{doctor?.name || 'Doctor'}</h3>
                <p className="text-blue-300 text-lg">{doctor?.specialty || 'Medical Specialist'}</p>
                <p className="text-gray-400 mt-2">Camera is off</p>
              </div>
            </div>

            {/* Local Video (Patient) - Picture in Picture */}
            <div className="absolute top-4 right-4 w-48 h-36 bg-gray-700 rounded-lg border-2 border-white shadow-lg">
              <div className="w-full h-full flex items-center justify-center text-white">
                {isVideoOn ? (
                  <div className="text-center">
                    <div className="w-16 h-16 bg-gradient-to-br from-green-500 to-green-600 rounded-full flex items-center justify-center text-white text-xl font-bold mx-auto mb-2">
                      YOU
                    </div>
                    <p className="text-xs">Your camera</p>
                  </div>
                ) : (
                  <div className="text-center">
                    <FaVideoSlash className="text-2xl mb-2" />
                    <p className="text-xs">Camera off</p>
                  </div>
                )}
              </div>
            </div>
          </>
        ) : (
          /* Audio Call Interface */
          <div className="w-full h-full bg-gradient-to-br from-blue-900 to-purple-900 flex items-center justify-center">
            <div className="text-center text-white">
              <div className="w-40 h-40 bg-gradient-to-br from-blue-500 to-blue-600 rounded-full flex items-center justify-center text-white text-5xl font-bold mx-auto mb-6">
                {doctor?.name ? doctor.name.split(' ').map(n => n[0]).join('') : 'DR'}
              </div>
              <h3 className="text-3xl font-semibold mb-2">{doctor?.name || 'Doctor'}</h3>
              <p className="text-blue-300 text-xl mb-4">{doctor?.specialty || 'Medical Specialist'}</p>
              <div className="flex items-center justify-center gap-2 text-green-400">
                <div className="w-3 h-3 bg-green-400 rounded-full animate-pulse"></div>
                <span className="text-lg">Connected</span>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Call Controls */}
      <div className="bg-gray-800 p-6">
        <div className="flex items-center justify-center gap-6">
          {/* Mute/Unmute */}
          <button
            onClick={() => setIsMuted(!isMuted)}
            className={`p-4 rounded-full transition-all duration-200 ${
              isMuted 
                ? 'bg-red-500 hover:bg-red-600 text-white' 
                : 'bg-gray-600 hover:bg-gray-500 text-white'
            }`}
            aria-label={isMuted ? 'Unmute' : 'Mute'}
          >
            {isMuted ? <FaMicrophoneSlash className="text-xl" /> : <FaMicrophone className="text-xl" />}
          </button>

          {/* Video On/Off (only for video calls) */}
          {callType === 'video' && (
            <button
              onClick={() => setIsVideoOn(!isVideoOn)}
              className={`p-4 rounded-full transition-all duration-200 ${
                !isVideoOn 
                  ? 'bg-red-500 hover:bg-red-600 text-white' 
                  : 'bg-gray-600 hover:bg-gray-500 text-white'
              }`}
              aria-label={isVideoOn ? 'Turn off camera' : 'Turn on camera'}
            >
              {isVideoOn ? <FaVideo className="text-xl" /> : <FaVideoSlash className="text-xl" />}
            </button>
          )}

          {/* Switch Camera (only for video calls) */}
          {callType === 'video' && (
            <button
              className="p-4 rounded-full bg-gray-600 hover:bg-gray-500 text-white transition-all duration-200"
              aria-label="Switch camera"
            >
              <FaSync className="text-xl" />
            </button>
          )}

          {/* Chat */}
          <button
            className="p-4 rounded-full bg-gray-600 hover:bg-gray-500 text-white transition-all duration-200"
            aria-label="Open chat"
          >
            <FaComment className="text-xl" />
          </button>

          {/* End Call */}
          <button
            onClick={handleEndCall}
            className="p-4 rounded-full bg-red-500 hover:bg-red-600 text-white transition-all duration-200 transform hover:scale-105"
            aria-label="End call"
          >
            <FaPhone className="text-xl transform rotate-135" />
          </button>
        </div>

        {/* Call Info */}
        <div className="mt-4 text-center text-gray-300">
          <p className="text-sm">
            {isMuted && <span className="text-red-400 mr-2">🔇 Muted</span>}
            {callType === 'video' && !isVideoOn && <span className="text-red-400 mr-2">📹 Camera Off</span>}
            <span>Call with {doctor?.name || 'Doctor'}</span>
          </p>
        </div>
      </div>
    </div>
  );
};

export default VideoCallUI;
